"use client";
import {
  useQuery
} from "./chunk-XJZH5NMZ.mjs";
import {
  useAutumnClient
} from "./chunk-SOA7GEAN.mjs";

// src/react/hooks/useReferrals.ts
import { useCallback } from "react";
var useReferrals = (params) => {
  const client = useAutumnClient({ caller: "useReferrals" });
  const { programId, queryOptions } = params;
  const queryResult = useQuery({
    queryKey: ["autumn", "referrals", "create", programId],
    queryFn: () => client.createReferralCode({
      programId
    }),
    enabled: false,
    ...queryOptions
  });
  const redeemCode = useCallback(
    async (redeemParams) => {
      return client.redeemReferralCode(redeemParams);
    },
    [client]
  );
  return {
    ...queryResult,
    redeemCode
  };
};

export {
  useReferrals
};
